using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  sqlgen::sqlite::connect(db_path)
      .and_then([&records](auto&& conn) {
        return sqlgen::write(conn, records);
      })
      .value();
}

template<typename T>
void modify_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id,
                               const std::string& col_name,
                               const T& new_value) {
  if (table_name == "Student") {
    sqlgen::sqlite::connect(db_path)
        .and_then([&](auto&& conn) {
          return sqlgen::exec(conn, 
            "UPDATE Student SET " + col_name + " = ? WHERE SNo = ?",
            new_value, record_id);
        })
        .value();
  } else if (table_name == "Course") {
    auto id = std::stoul(record_id);
    sqlgen::sqlite::connect(db_path)
        .and_then([&](auto&& conn) {
          return sqlgen::exec(conn,
            "UPDATE Course SET " + col_name + " = ? WHERE CID = ?",
            new_value, id);
        })
        .value();
  } else if (table_name == "Score") {
    auto id = std::stoul(record_id);
    sqlgen::sqlite::connect(db_path)
        .and_then([&](auto&& conn) {
          return sqlgen::exec(conn,
            "UPDATE Score SET " + col_name + " = ? WHERE ScID = ?",
            new_value, id);
        })
        .value();
  } else if (table_name == "Major") {
    auto id = std::stoul(record_id);
    sqlgen::sqlite::connect(db_path)
        .and_then([&](auto&& conn) {
          return sqlgen::exec(conn,
            "UPDATE Major SET " + col_name + " = ? WHERE MID = ?",
            new_value, id);
        })
        .value();
  }
}

void delete_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id) {
  if (table_name == "Student") {
    sqlgen::sqlite::connect(db_path)
        .and_then([&record_id](auto&& conn) {
          return sqlgen::remove<Student>(conn) | where("SNo"_c == record_id);
        })
        .value();
  } else if (table_name == "Course") {
    auto id = std::stoul(record_id);
    sqlgen::sqlite::connect(db_path)
        .and_then([id](auto&& conn) {
          return sqlgen::remove<Course>(conn) | where("CID"_c == id);
        })
        .value();
  } else if (table_name == "Score") {
    auto id = std::stoul(record_id);
    sqlgen::sqlite::connect(db_path)
        .and_then([id](auto&& conn) {
          return sqlgen::remove<Score>(conn) | where("ScID"_c == id);
        })
        .value();
  } else if (table_name == "Major") {
    auto id = std::stoul(record_id);
    sqlgen::sqlite::connect(db_path)
        .and_then([id](auto&& conn) {
          return sqlgen::remove<Major>(conn) | where("MID"_c == id);
        })
        .value();
  }
}
```

**Key implementation details:**

1. **`add_eas_records`**: Uses `sqlgen::write` to insert a vector of records into the database. The template parameter `T` should be one of the struct types (Student, Course, Score, Major).

2. **`modify_eas_records_by_id`**: Updates a specific column of a record identified by its primary key. Since different tables have different column types, this uses a template parameter `T` for the new_value and uses `sqlgen::exec` with parameterized SQL for safety.

3. **`delete_eas_records_by_id`**: Removes a record by its primary key using `sqlgen::remove` with a `where` clause. Handles different primary key types (varchar for Student, uint32_t for others) by checking the table name.

All functions follow the monadic pattern of the `sqlgen` library using `and_then` for chaining operations and `.value()` to unwrap the result.

