```cpp
#pragma once

#include <filesystem>
#include <optional>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace test_design_eas_database {

  struct Student {
    sqlgen::PrimaryKey<std::string> SNo;
    std::string SName;
    std::optional<int> Sex;
    std::optional<std::string> Birthday;
    std::optional<int> Major;
    std::optional<float> Scorses;
    std::optional<std::string> Remark;
  };

  struct Course {
    sqlgen::PrimaryKey<int> CID;
    std::string CName;
    std::optional<int> Term;
    std::optional<int> CTime;
    float Credit;
  };

  struct Score {
    std::string SNo;
    int CID;
    std::optional<float> Score;
  };

  void design_eas_database() {
    // Connect to SQLite database
    auto db = sqlgen::sqlite::Connection("test_db.sqlite");

    // Create Student table
    db.create_table<Student>();

    // Create Course table
    db.create_table<Course>();

    // Create Score table with composite primary key and foreign keys
    // Since Score has a composite PK and FKs, we need custom SQL
    db.execute(R"(
      CREATE TABLE IF NOT EXISTS Score (
        SNo varchar(10) NOT NULL,
        CID int NOT NULL,
        Score float NULL,
        PRIMARY KEY (SNo, CID),
        FOREIGN KEY (SNo) REFERENCES Student(SNo),
        FOREIGN KEY (CID) REFERENCES Course(CID)
      )
    )");

    // Set default values for Student table
    db.execute("UPDATE Student SET Sex = 1 WHERE Sex IS NULL");
    db.execute("UPDATE Student SET Scorses = 0 WHERE Scorses IS NULL");

    // Set default values for Course table  
    db.execute("UPDATE Course SET Term = 1 WHERE Term IS NULL");
    db.execute("UPDATE Course SET Credit = 0 WHERE Credit IS NULL");
  }

}
```

