#include <sstream>

namespace query_active_users_posts {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

struct Post {
  sqlgen::PrimaryKey<int> post_id;
  int user_id;
  sqlgen::DateTime created_at;
};

struct ActiveUser {
  static constexpr const char* tablename = "ActiveUserView";
  static constexpr bool is_view = true;
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

std::vector<ActiveUser> query_active_users_posts() {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Connect to SQLite database
    auto conn = sqlgen::sqlite::Connection("test_db.sqlite");

    // Create User and Post tables
    conn.create_table<User>();
    conn.create_table<Post>();

    // Define date range for filtering
    auto start_date = DateTime("2025-12-01");
    auto end_date = DateTime("2025-12-31");

    // Create view for active users who posted between the specified dates
    // Using table aliases "u" for User and "p" for Post
    auto u = "u"_ns;
    auto p = "p"_ns;

    conn.create_view_as<ActiveUser>(
        select(u / &User::user_id, u / &User::username)
        .distinct()
        .from<User>(u)
        .inner_join<Post>(p, u / &User::user_id == p / &Post::user_id)
        .where(p / &Post::created_at >= start_date && p / &Post::created_at <= end_date)
    );

    // Query the view and return results
    return conn.select<ActiveUser>().exec();
}

}  // namespace query_active_users_posts
