#pragma once

#include <ranges>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace query_daily_traffic_metrics {

struct PageVisit {
  sqlgen::PrimaryKey<int> visit_id;
  std::string url;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> visit_time;
};

struct DailyTraffic {
  std::string visit_date;
  int total_visits;
  int unique_pages;
};

struct DailyTrafficView {
  static constexpr const char* tablename = "DailyTrafficView";
  static constexpr bool is_view = true;
  std::string visit_date;
  int total_visits;
  int unique_pages;
};

/**
 * Function: Calculate daily traffic metrics from a log table.
 * 
 * @return List of daily traffic metrics
 */
std::vector<DailyTraffic> query_daily_traffic_metrics() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Create or replace the view with the aggregation query
  conn.execute(R"(
    CREATE VIEW IF NOT EXISTS DailyTrafficView AS
    SELECT strftime('%Y-%m-%d', visit_time) as visit_date, 
           COUNT(*) as total_visits, 
           COUNT(DISTINCT url) as unique_pages
    FROM PageVisit
    GROUP BY visit_date
  )");

  // Query from the view and order by date
  auto results = select(from<DailyTrafficView>(conn))
    .order_by("visit_date"_f)
    .run();

  // Convert results to DailyTraffic vector
  std::vector<DailyTraffic> metrics;
  metrics.reserve(results.size());

  for (const auto& row : results) {
    metrics.push_back(DailyTraffic{
      .visit_date = row.visit_date,
      .total_visits = row.total_visits,
      .unique_pages = row.unique_pages
    });
  }

  return metrics;
}

}  // namespace query_daily_traffic_metrics
