namespace query_employee_hierarchy {

struct Employee {
  sqlgen::PrimaryKey<int> emp_id;
  std::string name;
  std::optional<int> manager_id;
};

struct EmployeeManager {
  std::string employee;
  std::optional<std::string> manager;
};

std::vector<EmployeeManager> query_employee_hierarchy() {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Connect to the SQLite database
    auto db = sqlite::connect("test_db.sqlite");

    // Execute the self-join query
    // This performs: SELECT e1.name as employee, e2.name as manager
    //                FROM Employee e1
    //                LEFT JOIN Employee e2 ON e1.manager_id = e2.emp_id
    auto results = db.execute(
        read<std::vector<EmployeeManager>> |
        from<Employee>("e1") |
        left_join<Employee>("e2", "e1.manager_id"_c == "e2.emp_id"_c) |
        select("e1.name"_c.as("employee"), "e2.name"_c.as("manager"))
    );

    return results;
}

}  // namespace query_employee_hierarchy
```

**Key points of the implementation:**

1. **Database Connection**: Uses `sqlite::connect()` to connect to "test_db.sqlite"

2. **Self-Join Setup**: 
   - `from<Employee>("e1")` - Creates the first table alias `e1`
   - `left_join<Employee>("e2", ...)` - Creates the second table alias `e2` for the self-join

3. **JOIN Condition**: Uses `"e1.manager_id"_c == "e2.emp_id"_c` to specify the join condition

4. **Column Selection**: 
   - Selects `e1.name` as `employee`
   - Selects `e2.name` as `manager` (optional to handle NULL managers)

5. **Result Mapping**: The `read<std::vector<EmployeeManager>>` maps the query results to the `EmployeeManager` struct

The LEFT JOIN ensures that employees without managers (where `manager_id` is NULL) are still included in the results with a `std::nullopt` for the manager field.

