std::vector<Book> query_search_books_by_criteria(const BookFilters& filters) {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Connect to the SQLite database
    auto conn = sqlgen::sqlite::connect("test_db.sqlite");

    // Read all books from the database
    auto all_books = conn.and_then(read<std::vector<Book>>).value();

    // Filter books based on the provided criteria
    std::vector<Book> result;
    std::copy_if(all_books.begin(), all_books.end(), std::back_inserter(result),
        [&filters](const Book& book) {
            // Filter by title (LIKE search - case-sensitive substring match)
            if (filters.title_keyword.has_value()) {
                if (book.title.find(*filters.title_keyword) == std::string::npos) {
                    return false;
                }
            }

            // Filter by minimum year (year >= min_year)
            if (filters.min_year.has_value()) {
                if (book.year < *filters.min_year) {
                    return false;
                }
            }

            // Filter by genre (exact match)
            if (filters.genre.has_value()) {
                if (book.genre != *filters.genre) {
                    return false;
                }
            }

            // Filter by maximum price (price <= max_price)
            if (filters.max_price.has_value()) {
                if (book.price > *filters.max_price) {
                    return false;
                }
            }

            return true;
        });

    return result;
}

}  // namespace query_search_books_by_criteria
