namespace schema_manage_indexes {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string sku;
  std::string name;
  std::string category;
  double price;
};

/**
 * Function: Create and manage indexes for performance optimization.
 * 
 * @return true if index creation succeeds, false otherwise
 */
bool manage_indexes() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  auto conn_result = sqlite::connect("test_db.sqlite");
  if (!conn_result) return false;
  auto conn = conn_result.value();

  // Create table if not exists
  create_table<Product>(conn);

  // 1. Create standard index on category
  auto idx1 = create_index<"idx_product_category", Product>("category"_c) | if_not_exists;
  auto res1 = idx1(conn);
  if (!res1) return false;

  // 2. Create unique index on sku
  auto idx2 = create_unique_index<"idx_product_sku", Product>("sku"_c) | if_not_exists;
  auto res2 = idx2(conn);
  if (!res2) return false;

  // 3. Create composite index on (name, price)
  auto idx3 = create_index<"idx_product_name_price", Product>("name"_c, "price"_c) | if_not_exists;
  auto res3 = idx3(conn);
  if (!res3) return false;

  return true;
}

}  // namespace schema_manage_indexes

