```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace soft_delete_records {

struct Document {
  sqlgen::PrimaryKey<int> doc_id;
  std::string title;
  int is_deleted = 0;
  std::optional<sqlgen::DateTime> deleted_at;
};

bool soft_delete_records(const std::vector<int>& ids) {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Return early if no IDs to process
    if (ids.empty()) {
        return true;
    }

    // Connect to the database
    auto conn = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn) {
        return false;
    }

    // Update each document in the list
    // Using iteration within a transaction as sqlgen prefers
    for (const auto& id : ids) {
        conn = std::move(conn).and_then([id](auto c) {
            // Execute the update for this specific document ID
            // Set is_deleted to 1 and deleted_at to current timestamp
            return c.template execute(
                "UPDATE Document SET is_deleted = 1, deleted_at = CURRENT_TIMESTAMP WHERE doc_id = ?",
                id
            ).transform([c = std::move(c)](auto&&) { return c; });
        });

        if (!conn) {
            return false;
        }
    }

    return true;
}

}  // namespace soft_delete_records
```

