```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  using namespace sqlgen;

  try {
    // Connect to the database
    auto db = sqlgen::sqlite::connect("test_db.sqlite");

    // Begin transaction
    db.exec("BEGIN TRANSACTION");

    // Deduct from sender account (only if sufficient balance)
    // This will only update if balance >= amount
    auto rows_affected = db.exec(
      "UPDATE Account SET balance = balance - ? WHERE account_id = ? AND balance >= ?",
      amount, from_account_id, amount
    );

    // Check if deduction succeeded (row was updated)
    if (rows_affected == 0) {
      // Insufficient funds or account doesn't exist
      db.exec("ROLLBACK");
      return false;
    }

    // Add to receiver account
    db.exec(
      "UPDATE Account SET balance = balance + ? WHERE account_id = ?",
      amount, to_account_id
    );

    // Commit transaction
    db.exec("COMMIT");
    return true;

  } catch (const std::exception&) {
    // Rollback on any error
    try {
      auto db = sqlgen::sqlite::connect("test_db.sqlite");
      db.exec("ROLLBACK");
    } catch (...) {
      // Ignore rollback errors
    }
    return false;
  }
}

}  // namespace transaction_transfer_funds
