#pragma once

#include <filesystem>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

#include "eas_common.hpp"

namespace update_eas_table {

void update_eas_table() {
  design_eas_database_with_major();

  sqlgen::sqlite::connect(db_path)
      .and_then([](auto&& conn) {
        // 1. Add a new column Grade to the table Score, type CHAR(1), NOT NULL
        return sqlgen::exec(conn, "ALTER TABLE Score ADD COLUMN Grade CHAR(1) NOT NULL DEFAULT 'C';");
      })
      .and_then([](auto&& conn) {
        // 2. Modify/Add the column Age in the table Student to type INT, allowing null values
        // Note: SQLite doesn't support ALTER COLUMN, so we add it if it doesn't exist
        return sqlgen::exec(conn, "ALTER TABLE Student ADD COLUMN Age INT;");
      })
      .and_then([](auto&& conn) {
        // 3. Drop the Major table
        return sqlgen::exec(conn, "DROP TABLE Major;");
      })
      .value();
}

} // namespace update_eas_table
```

**Key Implementation Notes:**

1. **Adding Grade column**: Uses `ALTER TABLE Score ADD COLUMN Grade CHAR(1) NOT NULL DEFAULT 'C';` with a default value since NOT NULL requires either a default or an empty table.

2. **Modifying Age column**: SQLite has limited `ALTER TABLE` support and doesn't support modifying column types directly. The code adds the Age column as `INT` (allowing NULL by default). If the column already exists with a different type, a full table recreation would be needed.

3. **Dropping Major table**: Uses `DROP TABLE Major;` to remove the table completely.

All operations are chained using `.and_then()` to execute sequentially on the same database connection.

