```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace right_join_departments_projects {

struct Department {
  sqlgen::PrimaryKey<int> department_id;
  std::string name;
};

struct Project {
  sqlgen::PrimaryKey<int> project_id;
  int department_id;
  std::string name;
};

struct DepProj {
  std::optional<std::string> department_name;
  std::string project_name;
};

/**
 * description: right_join_departments_projects.
 * This function demonstrates how to perform a right join between departments and projects using sqlgen read API.
 * It returns a vector of DepProj structs, where each struct contains the department name (if available) and the project name.
 * Returns: std::vector<DepProj>.
 */
std::vector<DepProj> right_join_departments_projects() {
  using namespace sqlgen;

  // Connect to the SQLite database
  auto conn = sqlite::connect("test_db.sqlite");

  // SQLite doesn't natively support RIGHT JOIN, so we emulate it using LEFT JOIN
  // Based on the DepProj structure (optional department_name, required project_name),
  // we want all projects, even those without matching departments
  // This is: Project LEFT JOIN Department (to get all projects)
  // Which is equivalent to: Department RIGHT JOIN Project

  auto result = conn.and_then([](auto db) -> sqlgen::Result<std::vector<DepProj>> {
    // Execute the RIGHT JOIN query (emulated as LEFT JOIN for SQLite)
    const std::string query = R"(
      SELECT d.name as department_name, p.name as project_name
      FROM Project p
      LEFT JOIN Department d ON p.department_id = d.department_id
    )";

    return db.template execute_query<std::vector<DepProj>>(query);
  });

  // Return the result, or an empty vector if there was an error
  return result.value_or(std::vector<DepProj>{});
}

}  // namespace right_join_departments_projects
```

This implementation:

1. **Connects to the SQLite database** "test_db.sqlite" using `sqlite::connect()`
2. **Performs a RIGHT JOIN** (emulated as LEFT JOIN since SQLite doesn't support RIGHT JOIN natively) between Project and Department tables
3. **Includes all projects** (even those without matching departments), as indicated by the `DepProj` structure where `department_name` is optional but `project_name` is required
4. **Returns a vector of DepProj** structs containing the joined results

The query selects department names (which can be NULL/optional) and project names from all projects, matching them with departments where the relationship exists.

