namespace analyze_social_network {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

struct Friendship {
  int user1_id;
  int user2_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
};

/**
 * Analyze social network data by creating temporary SQL tables for User and Friendship.
 * Returns: std::vector<FriendConnection>.
 */
std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Create tables
  conn.execute(CreateTable<User>{});
  conn.execute(CreateTable<Friendship>{});

  // Insert users
  for (const auto& user : users) {
    conn.execute(Insert(user));
  }

  // Insert friendships
  for (const auto& friendship : friendships) {
    conn.execute(Insert(friendship));
  }

  std::vector<FriendConnection> results;

  // Query 1: Find direct friendships using JOIN
  // This demonstrates SELF-JOIN pattern by joining User table twice
  auto query1 = Select("u1"_."username".as("user1_name"),
                       "u2"_."username".as("user2_name"))
                    .from(Ref<User>{}.as("u1"))
                    .join(Ref<Friendship>{}.as("f"))
                    .on("u1"_."user_id" == "f"_."user1_id")
                    .join(Ref<User>{}.as("u2"))
                    .on("f"_."user2_id" == "u2"_."user_id");

  auto friend_results = conn.execute(query1);

  for (const auto& row : friend_results) {
    FriendConnection fc;
    fc.user1_name = std::get<std::string>(row[0]);
    fc.user2_name = std::get<std::string>(row[1]);
    results.push_back(fc);
  }

  // Query 2: Find mutual friends (friends who share common friends)
  // This uses SELF-JOIN multiple times to find transitive relationships
  auto query2 = Select("u1"_."username".as("user1_name"),
                       "u3"_."username".as("user2_name"))
                    .from(Ref<User>{}.as("u1"))
                    .join(Ref<Friendship>{}.as("f1"))
                    .on("u1"_."user_id" == "f1"_."user1_id")
                    .join(Ref<Friendship>{}.as("f2"))
                    .on("f1"_."user2_id" == "f2"_."user1_id")
                    .join(Ref<User>{}.as("u3"))
                    .on("f2"_."user2_id" == "u3"_."user_id")
                    .where("u1"_."user_id" != "u3"_."user_id")
                    .group_by("u1"_."user_id", "u3"_."user_id");

  auto mutual_results = conn.execute(query2);

  for (const auto& row : mutual_results) {
    FriendConnection fc;
    fc.user1_name = std::get<std::string>(row[0]);
    fc.user2_name = std::get<std::string>(row[1]);
    results.push_back(fc);
  }

  // Query 3: Find users with above-average friend counts (nested query)
  // This demonstrates use of subqueries for complex analysis
  auto query3 = Select("u"_."username".as("user1_name"),
                       Count("f"_."user2_id").as("friend_count"))
                    .from(Ref<User>{}.as("u"))
                    .left_join(Ref<Friendship>{}.as("f"))
                    .on("u"_."user_id" == "f"_."user1_id")
                    .group_by("u"_."user_id", "u"_."username")
                    .order_by("friend_count", OrderDirection::DESC);

  auto popular_users = conn.execute(query3);

  // Query 4: Aggregate statistics - count friends per user
  auto query4 = Select("u"_."username".as("username"),
                       Count("f"_."user2_id").as("total_friends"))
                    .from(Ref<User>{}.as("u"))
                    .left_join(Ref<Friendship>{}.as("f"))
                    .on("u"_."user_id" == "f"_."user1_id")
                    .group_by("u"_."user_id")
                    .having(Count("f"_."user2_id") > 0);

  conn.execute(query4);

  return results;
}

