  auto c_discount_rate = "discount_rate"_c;
  auto c_tax_rate = "tax_rate"_c;

  // Calculate metrics using SQL arithmetic operations
  auto gross_total = c_unit_price * c_quantity;
  auto discounted_total = c_unit_price * c_quantity * 
                          (1.0 - coalesce(c_discount_rate, 0.0) / 100.0);
  auto final_total = c_unit_price * c_quantity * 
                     (1.0 - coalesce(c_discount_rate, 0.0) / 100.0) * 
                     (1.0 + coalesce(c_tax_rate, 0.0) / 100.0);
  auto unit_cost = c_unit_price * c_quantity / c_quantity;
  auto quantity_group = c_quantity % 10;
  auto estimated_profit = c_unit_price * 0.3;

  // Execute query with calculated fields
  auto results = read<std::vector<OrderMetrics>>(
    conn,
    select(
      c_item_id,
      c_order_id,
      c_product_id,
      c_unit_price,
      c_quantity,
      coalesce(c_discount_rate, 0.0).as("discount_rate"),
      coalesce(c_tax_rate, 0.0).as("tax_rate"),
      gross_total.as("gross_total"),
      discounted_total.as("discounted_total"),
      final_total.as("final_total"),
      unit_cost.as("unit_cost"),
      quantity_group.as("quantity_group"),
      estimated_profit.as("estimated_profit")
    ).from<OrderItem>()
  ).value();

  return results;
}

}  // namespace calculate_order_metrics
