#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace full_join_suppliers_products {

struct Supplier {
  sqlgen::PrimaryKey<int> supplier_id;
  std::string name;
};

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int supplier_id;
  std::string name;
};

struct SupProd {
  std::string supplier_name;
  std::optional<std::string> product_name;
};

/**
 * Returns a vector of SupProd structs, where each struct contains the name of a supplier and the name of a product, if any.
 */
std::vector<SupProd> full_join_suppliers_products() {
  using namespace sqlgen;

  // Connect to the SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // SQLite doesn't natively support FULL OUTER JOIN
  // We simulate it using LEFT JOIN to get all suppliers with their products (or NULL)
  // UNION with products that don't have a matching supplier

  // SQL query for FULL OUTER JOIN simulation:
  // 1. LEFT JOIN: All suppliers with their matching products (product can be NULL)
  // 2. UNION: Products without matching suppliers (supplier would be empty/NULL)
  std::string full_join_query = R"(
    SELECT s.name as supplier_name, p.name as product_name
    FROM Supplier s
    LEFT JOIN Product p ON s.supplier_id = p.supplier_id
    UNION
    SELECT COALESCE(s.name, '') as supplier_name, p.name as product_name
    FROM Product p
    LEFT JOIN Supplier s ON p.supplier_id = s.supplier_id
    WHERE s.supplier_id IS NULL
  )";

  // Execute the query and return results
  // Based on the library patterns, using read with custom query or execute
  auto result = conn.and_then(sqlgen::read<std::vector<SupProd>>(full_join_query));

  return result.value_or(std::vector<SupProd>{});
}

}  // namespace full_join_suppliers_products
