namespace get_top_products {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string product_name;
  std::string category;
  double price;
};

struct Sales {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Date sale_date;
};

struct TopProduct {
  int product_id;
  std::string product_name;
  std::string category;
  double total_sales;
};

/**
 * Description: This function retrieves the top products based on total sales.
 * Returns: std::vector<TopProduct>.
 */
std::vector<TopProduct> get_top_products(size_t limit_count = 10) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  if (!conn) {
    return std::vector<TopProduct>{};
  }

  // Execute query: Join Product and Sales tables, calculate total sales,
  // group by product, order by total sales descending, and apply limit
  auto result = conn
    .and_then([limit_count](auto db) {
      // Perform the join query with aggregation
      return sqlgen::query(db)
        .select<TopProduct>(
          "p.product_id"_c,
          "p.product_name"_c,
          "p.category"_c,
          sqlgen::sum("p.price"_c * "s.quantity"_c).as("total_sales"_c)
        )
        .from<Product>("p"_c)
        .join<Sales>("s"_c)
        .on("p.product_id"_c == "s.product_id"_c)
        .group_by("p.product_id"_c, "p.product_name"_c, "p.category"_c)
        .order_by(sqlgen::desc("total_sales"_c))
        .limit(limit_count)
        .execute();
    });

  return result.value_or(std::vector<TopProduct>{});
}

}  // namespace get_top_products
