# Complete file contents:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace weekday_sales_analysis {

struct Sales {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> sale_time;
};

struct WeekdayStats {
  int weekday;
  int total_quantity;
};

/**
 * Description: This function analyzes sales data to calculate total quantity sold for each weekday.
 * Returns: std::vector<WeekdayStats>.
 */
std::vector<WeekdayStats> weekday_sales_analysis() {
  // Connect to the SQLite database
  auto db = sqlgen::sqlite::connect("test_db.sqlite");

  // SQL query to extract weekday and aggregate quantities
  // strftime('%w', sale_time) returns weekday as 0-6 (0=Sunday, 1=Monday, ..., 6=Saturday)
  const std::string query = R"(
    SELECT CAST(strftime('%w', sale_time) AS INTEGER) as weekday,
           SUM(quantity) as total_quantity
    FROM Sales
    GROUP BY strftime('%w', sale_time)
    ORDER BY weekday
  )";

  // Execute query and return results mapped to WeekdayStats structure
  return db.execute<WeekdayStats>(query);
}

}  // namespace weekday_sales_analysis
```

**Key implementation details:**

1. **Database Connection**: Uses `sqlgen::sqlite::connect()` to connect to "test_db.sqlite"

2. **Weekday Extraction**: Uses SQLite's `strftime('%w', sale_time)` function which returns:
   - 0 = Sunday
   - 1 = Monday
   - 2 = Tuesday
   - 3 = Wednesday
   - 4 = Thursday
   - 5 = Friday
   - 6 = Saturday

3. **Aggregation**: Uses `SUM(quantity)` grouped by weekday to calculate total quantity sold per weekday

4. **Result Mapping**: The query results are automatically mapped to the `WeekdayStats` structure with matching field names (`weekday` and `total_quantity`)

5. **Ordering**: Results are ordered by weekday for consistent output

